async (params, browser) => {
  // Open collections page
  await browser.open(`${params.store_url}/collections`)

  // Wait for collections page to load
  await browser.waitForSelector('body', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to load more collections
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(1000)

  // Extract collections
  const collections_data = await browser.evaluate(`const collections = []; const collectionCards = document.querySelectorAll('.collection-list__item, .grid__item, .collection-card, [class*="CollectionCard"], [class*="collection-card"], .list-collections__item'); for (let i = 0; i < Math.min(collectionCards.length, 30); i++) { const card = collectionCards[i]; const linkEl = card.querySelector('a[href*="/collections/"]'); const nameEl = card.querySelector('h2, h3, .card__heading, .collection-card__title, [class*="title"]'); const imgEl = card.querySelector('img'); const countEl = card.querySelector('[class*="count"], .collection-card__count, .badge'); if (linkEl || nameEl) { collections.push({ name: nameEl ? nameEl.textContent.trim() : (linkEl ? linkEl.textContent.trim() : ''), url: linkEl ? linkEl.href : '', image: imgEl ? (imgEl.src || imgEl.dataset.src || '') : '', product_count: countEl ? countEl.textContent.trim() : '' }); } } if (collections.length === 0) { const links = document.querySelectorAll('a[href*="/collections/"]'); const seen = new Set(); links.forEach(function(a) { const href = a.href; if (seen.has(href) || href.includes('/collections/all')) return; seen.add(href); const text = a.textContent.trim(); if (text && text.length > 1 && text.length < 100) { collections.push({ name: text, url: href, image: '', product_count: '' }); } }); } return { collection_count: collections.length, collections: collections, url: window.location.href }`)

  return collections_data
}
